def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0.0
        decay = 1.0
        threshold1 = 0.3
        threshold2 = 0.6
        threshold3 = 1.0
        phase = 0
        for step in range(10):
            if ratio > threshold3:
                score += 100 * decay
                phase = 3
                break
            if ratio < 1e-5:
                score += 0.05 * decay
                phase = 0
                break
            exp_term = np.exp(-ratio * (step + 1) * 1.5)
            tanh_term = np.tanh(ratio * 15 * (step + 1))
            log_term = np.log1p(ratio * 150) / (step + 3)
            sin_term = (np.sin(ratio * np.pi * (step + 0.25)))**3
            score += (exp_term + tanh_term + log_term + sin_term) * decay
            if ratio < threshold1:
                score += (6 - step) * 0.4 * decay
                if step % 2 == 0:
                    score -= 0.1 * step * decay
            elif threshold1 <= ratio < threshold2:
                score -= step * 0.7 * decay
            elif threshold2 <= ratio < threshold3:
                score += step * 0.3 * decay
            else:
                score += 1.2 * step * decay
            decay *= 0.65
            if score > 20:
                phase = 2
                break
        if phase == 0:
            for k in range(4):
                penalty = ((0.4 / (k + 1)) * (1 - ratio)) ** 3
                score += penalty
                if penalty > 0.5:
                    score -= 0.2 * k
        elif phase == 2:
            for k in range(3):
                if capacity < item * (1 + 0.05 * k):
                    score += 4 * (k + 1)
                else:
                    score -= 0.5 * (k + 1)
        if capacity < item * 0.9:
            score += 30
        elif capacity > item * 2.5:
            score /= 3
        if score < 0:
            score = 0
        priorities[i] = score
    finite = priorities[np.isfinite(priorities)]
    if finite.size == 0:
        return np.full_like(priorities, float('inf'))
    p_min = np.min(finite)
    p_max = np.max(finite)
    range_p = p_max - p_min if p_max != p_min else 1
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = p_min * 300
        else:
            if priorities[i] == p_min:
                priorities[i] = 0
            elif priorities[i] == p_max:
                priorities[i] *= 2
            else:
                priorities[i] = ((priorities[i] - p_min) / range_p) ** 1.5 * 25
    return priorities
